#include <bits/stdc++.h>
using namespace std;
int jg(int n) {
	if(n==1) {
		return 0;
	}
	if(n%2==1) {
		cout<<n<<"*3+1="<<n*3+1<<"\n";
		return jg(n*3+1);
	}
	cout<<n<<"/2="<<n/2<<"\n";
	return jg(n/2);
}
int main() {
	unsigned long long n;
	cin>>n;
	jg(n);
	cout<<"End";
	return 0;
}
